  test('supports a mix of present and missing values', () => {
    expect(normalizeSettings({
      retryCount: 5,
      subtitle: '',
      emailOptIn: undefined
    })).toEqual({
      retryCount: 5,
      subtitle: '',
      emailOptIn: true
    });
  });
});

