export default function createClickTracker(label){
  return {
    label,
    count: 0,
    recordClick(){
      this.count += 1;
      return `${this.label}:${this.count}`;
    },
    attach(register){
      return register(this.recordClick);
    }
  };
}

tests:
import createClickTracker from './js-debug-lost-this-binding';

describe('createClickTracker', () => {
  test('still works when called directly as a method', () => {
    const tracker = createClickTracker('save');
    expect(tracker.recordClick()).toBe('save:1');
  });

  test('keeps the tracker context when a callback API invokes it later', () => {
    const tracker = createClickTracker('save');
    tracker.recordClick();
    const result = tracker.attach((handler) => handler());
    expect(result).toBe('save:2');
    expect(tracker.count).toBe(2);
  });

  test('supports repeated callback calls without losing state', () => {
    const tracker = createClickTracker('open');
    const result = tracker.attach((handler) => [handler(), handler()]);
    expect(result).toEqual(['open:1', 'open:2']);
    expect(tracker.count).toBe(2);
  });
});

solution:
export default function createClickTracker(label){
  return {
    label,
    count: 0,
    recordClick(){
      this.count += 1;
      return `${this.label}:${this.count}`;
    },
    attach(register){
      // Detached methods lose their receiver, so bind before handing them off.
      return register(this.recordClick.bind(this));
    }
  };
}

